/// Look for patterns like
///   %sel1 = select i1 %c1, T %a, T %b
///   %sel2 = select i1 %c1, T %b, T %a
///   %ret = select i1 %c2, T %sel1, T %sel2
/// and rewrite it as
///   %xor = xor i1 %c1, %c2
///   %ret = select i1 %xor, T %b, T %a
static Instruction *foldSymmetricSelects(SelectInst &SI,
                                         InstCombiner::BuilderTy &Builder) {
  Value *OuterCond = SI.getCondition();
  Value *OuterTrue = SI.getTrueValue();
  Value *OuterFalse = SI.getFalseValue();

  // Check if both operands are selects
  auto *Sel1 = dyn_cast<SelectInst>(OuterTrue);
  auto *Sel2 = dyn_cast<SelectInst>(OuterFalse);
  if (!Sel1 || !Sel2)
    return nullptr;

  // Check if both inner selects have the same condition
  Value *InnerCond = Sel1->getCondition();
  if (InnerCond != Sel2->getCondition())
    return nullptr;

  // Check if the selects are symmetric (swapped operands)
  Value *A = Sel1->getTrueValue();
  Value *B = Sel1->getFalseValue();
  if (A != Sel2->getFalseValue() || B != Sel2->getTrueValue())
    return nullptr;

  // Create the XOR of the conditions
  Value *XorCond = Builder.CreateXor(InnerCond, OuterCond);

  // Create the new select: select (c1 xor c2), b, a
  return SelectInst::Create(XorCond, B, A);
}

